  power:{ro:'Putere',en:'Power',pt:'Poder',glyph:'光',color:'#F6D365',circle:{ro:'Cercul Puterii',en:'Circle of Power',pt:'Círculo do Poder'}},
  mind: {ro:'Minte', en:'Mind', pt:'Mente',glyph:'意',color:'#8FB8FF',circle:{ro:'Cercul Minții',en:'Circle of the Mind',pt:'Círculo da Mente'}},
